sql:
SELECT COUNT(*) 
FROM theses 
WHERE file_size > 500000;

SELECT thesis_title, thesis_year, abstract, file_size, file_format
FROM theses
WHERE author_id = 0;

SELECT authors.author_name, authors.email, authors.phone_number, employment_history.employer, employment_history.position
FROM authors
LEFT JOIN employment_history ON authors.author_id = employment_history.author_id;

SELECT thesis_title, abstract, file_size, file_format 
FROM theses 
WHERE thesis_id = 1;

external_knowledge:
A person having written a thesis refers to the number of entries associated with them in the "theses" table; 
A person's latest employer is assumed to be the last entry associated with them in the "employment history" table; 
This query assumes that an author has "no phone number" if the phone_number field in the authors table is NULL, and has an email if the email field is not NULL.

sql:
SELECT file_format, SUM(file_size) AS total_file_size
FROM theses
GROUP BY file_format;

SELECT author_name
FROM authors
WHERE author_name = 'John Doe';
